python3 -c "
import json
import sys

# Read schema and manifest
with open('schema.json', 'r') as f:
    schema = json.load(f)
with open('manifest.json', 'r') as f:
    manifest = json.load(f)

# Validate schema requirements manually
errors = []

# Check required fields
if 'release' not in manifest:
    errors.append('Missing required field: release')
if 'components' not in manifest:
    errors.append('Missing required field: components')

# Check release pattern
import re
if 'release' in manifest:
    if not re.match(r'^v[0-9]+\.[0-9]+\.[0-9]+$', manifest['release']):
        errors.append(f'Invalid release format: {manifest[\"release\"]}')

# Check components is array with exactly 3 items
if 'components' in manifest:
    if not isinstance(manifest['components'], list):
        errors.append('components must be an array')
    elif len(manifest['components']) != 3:
        errors.append(f'components must have exactly 3 items, got {len(manifest[\"components\"])}')

    # Check each component
    if isinstance(manifest['components'], list):
        required_order = ['catalog', 'fetcher', 'leaderboard']
        for i, comp in enumerate(manifest['components']):
            if not isinstance(comp, dict):
                errors.append(f'Component {i} must be an object')
                continue

            # Check required properties
            if 'name' not in comp:
                errors.append(f'Component {i} missing required property: name')
            if 'version' not in comp:
                errors.append(f'Component {i} missing required property: version')

            # Check no extra properties
            allowed = {'name', 'version'}
            extra = set(comp.keys()) - allowed
            if extra:
                errors.append(f'Component {i} has extra properties: {extra}')

            # Check version format
            if 'version' in comp and not re.match(r'^[0-9]+\.[0-9]+\.[0-9]+$', comp['version']):
                errors.append(f'Component {i} has invalid version format: {comp[\"version\"]}')

            # Check order
            if 'name' in comp and i < len(required_order):
                if comp['name'] != required_order[i]:
                    errors.append(f'Component {i} should be {required_order[i]}, got {comp[\"name\"]}')

# Check no additional properties
allowed = {'release', 'components'}
extra = set(manifest.keys()) - allowed
if extra:
    errors.append(f'Manifest has extra properties: {extra}')

if errors:
    print('Validation errors:')
    for error in errors:
        print(f'  - {error}')
    sys.exit(1)
else:
    print('✓ manifest.json validates against schema.json')
    print('✓ components is an array of exactly 3 ordered objects')
    print('✓ Each component has only name and version')
    print('✓ release is preserved as v2.4.0')
"
